// Primitives
const count = 42;         // number
const label = 'open';     // string
const active = true;      // boolean
const nothing = null;     // null

// TypeScript uses the inferred type for all subsequent checks
let score = 100;           // number
score = 200;               // OK
// score = 'high';         // TS2322 — cannot assign string to number

// Object literals
const point = { x: 10, y: 20 };
// point: { x: number; y: number }
// point.x = 99;  OK
// point.z = 5;   TS2339 — property 'z' does not exist

// Arrays
const nums = [1, 2, 3];   // number[]
const mixed = [1, 'a'];   // (string | number)[]
const empty = [];          // never[] — annotate if you'll push to it later
const items: string[] = []; // explicit annotation needed for empty arrays

// const → literal type preserved
const direction = 'north'; // type: 'north'  (string literal)
const code      = 404;     // type: 404       (number literal)

// let → widened to base type
let direction2 = 'north';  // type: string
let code2      = 404;      // type: number

// This matters for unions and function parameters
function navigate(dir: 'north' | 'south' | 'east' | 'west'): void { /* ... */ }

navigate(direction);  // OK — 'north' is assignable to the union
// navigate(direction2); // TS2345 — string is not assignable to the union

// Force literal type on let with a type annotation
let fixed: 'north' | 'south' = 'north'; // always a direction
fixed = 'south'; // OK
// fixed = 'east'; // TS2322

// Return type inferred from all return paths
function add(a: number, b: number) {
  return a + b; // inferred: number
}

// Inferred from conditional branches
function classify(n: number) {
  if (n > 0) return 'positive'; // string
  if (n < 0) return 'negative'; // string
  return 'zero';                 // string
  // return type: string
}

// Union return type — TypeScript unifies all return paths
function maybe(n: number) {
  if (n > 10) return n * 2; // number
  return null;               // null
  // return type: number | null
}

// Arrow functions — same rules
const double = (n: number) => n * 2; // (n: number) => number
const greet  = (name: string) => \`Hello \${name}\`; // (name: string) => string

// When to annotate explicitly:
// 1. Public APIs — documents the contract
// 2. Complex multi-branch functions — catches missing return paths
// 3. Recursive functions — inference can't work without a hint
function factorial(n: number): number {
  return n <= 1 ? 1 : n * factorial(n - 1);
}

// Callback parameters typed from the array method signature
const nums = [1, 2, 3];
nums.forEach(n => {
  // n: number — inferred from number[]
  console.log(n.toFixed(2));
});

nums.map(n => n * 2);          // n: number; return type: number[]
nums.filter(n => n > 1);       // n: number; return type: number[]

// Event handler — type comes from addEventListener signature
document.addEventListener('click', event => {
  // event: MouseEvent — inferred from the event name
  console.log(event.clientX, event.clientY);
});

// Object passed to a typed parameter
interface Config { host: string; port: number }
function connect(cfg: Config): void { /* ... */ }

connect({
  host: 'localhost', // TypeScript checks this against Config
  port: 3000,
  // extra: true,   // TS2345 — excess property not in Config
});

// Angular: template event binding context typing
// (click)="onClick($event)" — $event is MouseEvent in generated code

// TypeScript infers T from the argument
function identity<T>(value: T): T {
  return value;
}

const n = identity(42);      // T inferred as number
const s = identity('hello'); // T inferred as string

// Array utility — T inferred from the array
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}

const f1 = first([1, 2, 3]);    // T = number  → number | undefined
const f2 = first(['a', 'b']);   // T = string  → string | undefined

// Multiple type parameters inferred from call site
function zip<A, B>(a: A[], b: B[]): [A, B][] {
  return a.map((v, i) => [v, b[i]]);
}

const pairs = zip([1, 2], ['a', 'b']); // [number, string][]

// When explicit type argument is needed
// const empty = first([]);  // T = never — provide explicit arg
const empty = first<string>([]);  // T = string → string | undefined

// Capture the return type of any function
type ReturnType<T extends (...args: never[]) => unknown> =
  T extends (...args: never[]) => infer R ? R : never;

function fetchUser(): Promise<{ id: number; name: string }> {
  return Promise.resolve({ id: 1, name: 'Alice' });
}

type FetchResult = ReturnType<typeof fetchUser>;
// Promise<{ id: number; name: string }>

// Unwrap a Promise
type Awaited<T> = T extends Promise<infer U> ? U : T;
type User = Awaited<FetchResult>;
// { id: number; name: string }

// Extract array element type
type ElementOf<T> = T extends (infer E)[] ? E : never;
type StrEl = ElementOf<string[]>; // string
type NumEl = ElementOf<number[]>; // number

// Widening on let
let x = 'open';  // string — widened from 'open'

// Widening on object return
function getConfig() {
  return { mode: 'dark' }; // { mode: string } — not { mode: 'dark' }
}

// Prevent widening with as const
function getConfigConst() {
  return { mode: 'dark' } as const; // { readonly mode: 'dark' }
}

type Mode = 'dark' | 'light';
function applyMode(m: Mode): void { /* ... */ }

const cfg = getConfig();
// applyMode(cfg.mode); // TS2345 — string not assignable to Mode

const cfgConst = getConfigConst();
applyMode(cfgConst.mode); // OK — 'dark' is assignable to Mode

// as const also prevents widening on arrays
const dirs = ['north', 'south'] as const;
// readonly ['north', 'south'] — not string[]

function process(value: string | number): string {
  if (typeof value === 'string') {
    // value: string — narrowed
    return value.toUpperCase();
  }
  // value: number — narrowed (string excluded)
  return value.toFixed(2);
}

// instanceof narrowing
function handleError(e: unknown): string {
  if (e instanceof TypeError) return 'Type: ' + e.message; // e: TypeError
  if (e instanceof Error)     return 'Err: '  + e.message; // e: Error
  return String(e);                                          // e: unknown
}

// Truthiness narrowing
function display(label: string | null): string {
  if (label) {
    return label.trim(); // label: string (null excluded by truthiness)
  }
  return '(empty)';
}

// in operator narrowing
interface Cat { meow(): void }
interface Dog { bark(): void }
function speak(pet: Cat | Dog): void {
  if ('meow' in pet) pet.meow(); // pet: Cat
  else               pet.bark(); // pet: Dog
}

import { signal, computed } from '@angular/core';

// Signal infers type from initial value
const count = signal(0);        // Signal<number>
const label = signal('hello');  // Signal<string>
const user  = signal({ id: 1, name: 'Alice' }); // Signal<{ id: number; name: string }>

// computed infers return type from the computation
const doubled = computed(() => count() * 2); // Signal<number>
const upper   = computed(() => label().toUpperCase()); // Signal<string>

// update — callback parameter is inferred
count.update(prev => prev + 1); // prev: number

// When explicit type annotation is needed
const items = signal<string[]>([]); // infer would give Signal<never[]>

// Explicit typing for nullable initial state
const selectedUser = signal<{ id: number; name: string } | null>(null);

import { HttpClient } from '@angular/common/http';
import { map, filter } from 'rxjs/operators';

interface Product { id: number; name: string; price: number }

@Injectable({ providedIn: 'root' })
class ProductService {
  constructor(private http: HttpClient) {}

  // Generic argument tells HttpClient what shape to expect
  getAll() {
    return this.http.get<Product[]>('/api/products');
    // Observable<Product[]> — inferred from generic
  }

  // Operator return types are inferred through the pipeline
  getActive() {
    return this.http.get<Product[]>('/api/products').pipe(
      map(products => products.filter(p => p.price > 0)), // Product[]
      map(products => products.map(p => p.name)),          // string[]
    ); // Observable<string[]>
  }
}

// All elements share a supertype — inferred directly
const nums = [1, 2, 3];         // number[]
const mixed = [1, 'a', true];   // (string | number | boolean)[]

// Class hierarchy — best common type is the base class
class Animal { eat() {} }
class Dog extends Animal { bark() {} }
class Cat extends Animal { purr() {} }

const pets = [new Dog(), new Cat()]; // (Dog | Cat)[]
// Not Animal[] — TypeScript doesn't assume a base class unless
// you include one in the array

const withBase = [new Animal(), new Dog(), new Cat()]; // Animal[]
// Now Animal is a candidate, so all extend Animal → Animal[]

// When best common type fails — annotate explicitly
const petsAnnotated: Animal[] = [new Dog(), new Cat()]; // OK
petsAnnotated.forEach(p => p.eat()); // Animal methods available

// TypeScript unifies all return types
function parse(input: string | number | boolean): Date | string | number {
  if (typeof input === 'string') {
    const d = new Date(input);
    return isNaN(d.getTime()) ? input : d;  // Date | string
  }
  if (typeof input === 'boolean') {
    return input ? 1 : 0;  // number
  }
  return input;  // number
}
// Inferred return: Date | string | number

// Explicit annotation preferred for public APIs
function parseExplicit(input: string | number | boolean): Date | string | number {
  // Same body — annotation documents the contract
  if (typeof input === 'string') {
    const d = new Date(input);
    return isNaN(d.getTime()) ? input : d;
  }
  if (typeof input === 'boolean') return input ? 1 : 0;
  return input;
}

// Without predicate — TypeScript doesn't know what the check means
function isStringRaw(value: unknown): boolean {
  return typeof value === 'string';
}

const v: unknown = getData();
if (isStringRaw(v)) {
  // v: unknown — TypeScript doesn't narrow based on boolean return
  // v.toUpperCase(); // TS2571
}

// With type predicate — TypeScript narrows in the truthy branch
function isString(value: unknown): value is string {
  return typeof value === 'string';
}

if (isString(v)) {
  v.toUpperCase(); // OK — v: string inside this block
}

// Angular example — narrowing an event target
function isInputElement(el: EventTarget | null): el is HTMLInputElement {
  return el instanceof HTMLInputElement;
}

function handleInput(event: Event): void {
  if (isInputElement(event.target)) {
    console.log(event.target.value); // HTMLInputElement — value is available
  }
}

// ❌ Redundant — TypeScript infers all of these
const name: string = 'Alice';
const scores: number[] = [1, 2, 3];
const active: boolean = true;
const fn: (n: number) => number = (n) => n * 2;

// ✓ Annotate these — inference doesn't help or is wrong
const items: string[] = [];         // would be never[]
const result: string | null = null; // would be null

function fetchData(): Promise<User> { // documents the public contract
  return http.get<User>('/api/user').toPromise()!;
}

// ✓ Annotate function parameters — TypeScript never infers these
function greet(name: string, age: number): string {
  return `${name} is ${age}`;
}

// ✓ Annotate class properties that start null/undefined
class UserService {
  private user: User | null = null; // explicit — inference gives null
  private cache: Map<number, User> = new Map(); // inference OK here but explicit is clearer
}

// Complex inferred type — hard to read in IDE or error messages
function buildForm() {
  return {
    name: '',
    email: '',
    age: 0,
    roles: [] as string[],
    address: { street: '', city: '' },
  };
}
// Inferred: { name: string; email: string; age: number; roles: string[];
//            address: { street: string; city: string; } }

// Better — define the interface, let inference validate
interface UserForm {
  name: string;
  email: string;
  age: number;
  roles: string[];
  address: { street: string; city: string };
}

function buildForm2(): UserForm {
  return { name: '', email: '', age: 0, roles: [], address: { street: '', city: '' } };
}
// Errors appear here if a field is missing or wrong-typed
// Instead of at every call site
